// Merge all context: webhook body + setup vars + Graph token
const webhook = $('Webhook: OpsBlueprint Lead').first().json;
const setup = $('Setup Variables').first().json;
const tokenResp = $input.first().json;

const body = webhook.body || webhook;
const leadId = body.id || `OB-LEAD-${Date.now()}`;

// Build Azure OpenAI request for lead qualification
const systemPrompt = `You are a lead qualification assistant for OpsBlueprint, a workflow automation consulting firm.

Score this lead from 1-10 based on these factors:
- Clear pain point involving manual processes scores higher
- Multiple tools/platforms that need integration scores higher
- Larger team or company size scores higher
- Urgency expressed in their description scores higher
- Higher service tier interest (Professional, Enterprise, Managed) scores higher
- Vague requirements with no clear scope score lower
- Very small scope with no clear budget scores lower

Respond with JSON only:
{
  "qualificationScore": <1-10>,
  "qualificationNotes": "<2-3 sentence explanation of the score>",
  "suggestedTier": "<Starter|Professional|Enterprise|Managed>",
  "estimatedValue": "<dollar estimate based on scope and tier>",
  "urgency": "<high|medium|low>",
  "followUpRecommendation": "<specific next step for the consulting team>"
}`;

const userPrompt = `Qualify this automation consulting lead:

Name: ${body.fullName}
Email: ${body.email}
Company: ${body.company || 'Not provided'}
Industry: ${body.industry || 'Not provided'}
Problem Description: ${body.problemDescription || 'Not provided'}
Service Tier Interest: ${body.serviceTier || 'Not specified'}
Source: ${body.source || 'Website'}`;

return [{
  json: {
    ...setup,
    accessToken: tokenResp.access_token,
    lead: body,
    leadId,
    aoaiBody: {
      messages: [
        { role: 'system', content: systemPrompt },
        { role: 'user', content: userPrompt }
      ],
      max_completion_tokens: 1000,
      response_format: { type: 'json_object' }
    }
  }
}];

// Parse AI qualification result and prepare for Excel + Email
const prev = $('Build AI Qualification').first().json;
const aiResp = $input.first().json;

let qualification;
try {
  const content = aiResp.choices[0].message.content;
  qualification = JSON.parse(content);
} catch (e) {
  qualification = {
    qualificationScore: 5,
    qualificationNotes: 'AI parsing failed â€” manual review needed',
    suggestedTier: 'Professional',
    estimatedValue: 'Unknown',
    urgency: 'medium',
    followUpRecommendation: 'Contact lead directly for more details'
  };
}

const lead = prev.lead;
const now = new Date().toISOString();

// Excel row values (must match OBLeadsTable column order exactly)
const excelRow = [
  prev.leadId,
  lead.fullName || '',
  lead.email || '',
  lead.company || '',
  lead.industry || '',
  lead.problemDescription || '',
  lead.serviceTier || '',
  lead.source || '',
  String(qualification.qualificationScore),
  qualification.qualificationNotes,
  qualification.suggestedTier,
  qualification.estimatedValue,
  qualification.urgency,
  qualification.followUpRecommendation,
  'New',
  '',
  now
];

// Confirmation email HTML
const emailHtml = `
<div style="font-family: 'Inter', Arial, sans-serif; max-width: 600px; margin: 0 auto; color: #333;">
  <div style="background: #1E293B; padding: 30px; text-align: center;">
    <h1 style="color: #0D9488; margin: 0; font-size: 24px;">OpsBlueprint</h1>
    <p style="color: #94A3B8; margin: 5px 0 0;">Workflow Automation Consulting</p>
  </div>
  <div style="padding: 30px; background: #f9f9f9;">
    <h2 style="color: #1E293B;">Thank you, ${lead.fullName}!</h2>
    <p>We've received your automation consulting inquiry and are excited to help streamline your operations.</p>
    <div style="background: #fff; border-left: 4px solid #0D9488; padding: 15px; margin: 20px 0;">
      <p style="margin: 0;"><strong>Company:</strong> ${lead.company || 'Not provided'}</p>
      <p style="margin: 5px 0;"><strong>Industry:</strong> ${lead.industry || 'Not provided'}</p>
      <p style="margin: 5px 0;"><strong>Service Interest:</strong> ${lead.serviceTier || 'Not specified'}</p>
    </div>
    <p>Our team will review your inquiry and reach out within 1-2 business days to schedule a free 30-minute discovery call.</p>
    <p style="margin-top: 20px;">In the meantime, here's what to expect:</p>
    <ol style="color: #475569;">
      <li>We'll review your automation needs</li>
      <li>Schedule a discovery call</li>
      <li>Provide a detailed proposal with scope and ROI estimate</li>
    </ol>
  </div>
  <div style="background: #1E293B; padding: 20px; text-align: center;">
    <p style="color: #94A3B8; margin: 0; font-size: 12px;">OpsBlueprint | opsblueprint.fernando-vargas.com</p>
  </div>
</div>`;

return [{
  json: {
    accessToken: prev.accessToken,
    driveId: prev.driveId,
    leadsTrackerFileId: prev.leadsTrackerFileId,
    mailUserUpn: prev.mailUserUpn,
    leadId: prev.leadId,
    lead,
    qualification,
    excelRow,
    emailHtml,
    emailSubject: `OpsBlueprint â€” We received your inquiry, ${lead.fullName}!`
  }
}];
